// // This module implements a synchronous D flip-flop with an asynchronous reset.
module d_flip_flop(
    input clk,
    input d,
    input rst,
    output reg q
);

    always @(posedge clk or posedge rst) begin
        if (rst)
            q <= 1'b0;
        else
            q <= d;
    end

endmodule
